import { useEffect, useState } from "react";

export default function HackerDashboard() {
  const [role, setRole] = useState("");

  useEffect(() => {
    const storedRole = localStorage.getItem("role");
    const token = localStorage.getItem("token");

    // 🔒 If not logged in, go back to login
    if (!token) {
      window.location.href = "/";
      return;
    }

    setRole(storedRole || "");
  }, []);

  return (
    <div className="min-h-screen bg-gray-100 p-8">
      <h1 className="text-3xl font-bold mb-2">🧑‍💻 Hacker Dashboard</h1>
      <p className="text-gray-600 mb-6">Role: {role}</p>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        
        {/* SUBMIT BUG */}
        <div
          className="bg-white p-4 rounded shadow cursor-pointer hover:bg-gray-50"
          onClick={() => (window.location.href = "/submit-bug")}
        >
          <h2 className="font-semibold">🐞 Submit Bug</h2>
          <p className="text-sm text-gray-600">Report a new vulnerability</p>
        </div>

        {/* MY BUGS */}
        <div
          className="bg-white p-4 rounded shadow cursor-pointer hover:bg-gray-50"
          onClick={() => (window.location.href = "/my-bugs")}
        >
          <h2 className="font-semibold">📄 My Bugs</h2>
          <p className="text-sm text-gray-600">Track submitted bugs</p>
        </div>

        {/* WALLET */}
        <div
          className="bg-white p-4 rounded shadow cursor-pointer hover:bg-gray-50"
          onClick={() => (window.location.href = "/wallet")}
        >
          <h2 className="font-semibold">💰 Wallet</h2>
          <p className="text-sm text-gray-600">View rewards & balance</p>
        </div>
      </div>

      {/* LOGOUT */}
      <button
        className="mt-8 bg-red-500 text-white px-4 py-2 rounded"
        onClick={() => {
          localStorage.clear();
          window.location.href = "/";
        }}
      >
        Logout
      </button>
    </div>
  );
}
